import{_ as e,o as t,c as o,a0 as n}from"./chunks/framework.jwovEGr5.js";const p=JSON.parse('{"title":"Introduction to SwiftList","description":"","frontmatter":{},"headers":[],"relativePath":"guide/introduction.md","filePath":"guide/introduction.md"}'),s={name:"guide/introduction.md"};function r(a,i,l,d,c,g){return t(),o("div",null,[...i[0]||(i[0]=[n('<h1 id="introduction-to-swiftlist" tabindex="-1">Introduction to SwiftList <a class="header-anchor" href="#introduction-to-swiftlist" aria-label="Permalink to &quot;Introduction to SwiftList&quot;">​</a></h1><p>SwiftList is a high-performance, low-overhead, and highly extensible global search utility designed for Windows. It quickly builds and maintains indexes for local files, while offering a plugin SDK for developers to extend its capabilities.</p><h2 id="core-design-principles" tabindex="-1">Core Design Principles <a class="header-anchor" href="#core-design-principles" aria-label="Permalink to &quot;Core Design Principles&quot;">​</a></h2><ol><li><strong>YAGNI (You Aren&#39;t Gonna Need It)</strong>: Refuse bloated design; keep logic concise and execution fast.</li><li><strong>Process Separation &amp; Isolation</strong>: <ul><li><strong><code>SwiftList.Service</code> (System Service - <code>--service</code>)</strong>: Runs in Session 0 with SYSTEM privileges, indexing NTFS MFT and USN logs, shared globally.</li><li><strong><code>SwiftList.Service</code> (Hook Process - <code>--hook</code>)</strong>: Runs in the user session, capturing global keyboard hotkeys and tracking explorer paths.</li><li><strong><code>SwiftList.App</code> (User Application)</strong>: Runs in the user session, hosting UI interactions, rendering search results, and loading user-scoped plugins.</li></ul></li><li><strong>High-Speed FZF Matching</strong>: Optimized search matching supporting fuzzy queries, Pinyin initials, and customized aliases.</li></ol>',4)])])}const h=e(s,[["render",r]]);export{p as __pageData,h as default};
